        absolute_path = self._storage(location).path_on_disk(path)
        _, file_name = self._storage(location).split_path(path)
        file_type = get_file_type(absolute_path)

        if file_type:
            return QueueEntry(
                file_name,
                path_in_storage,
                file_type[-1],
                location,
                absolute_path,
                printer_profile,
                analysis,
            )
        else:
            return None

